"use client"

import React, { useState, useRef, Suspense } from "react"
// 3D Imports
import { Canvas, useFrame } from "@react-three/fiber"
import { Sphere, MeshDistortMaterial, Float, Stars } from "@react-three/drei"
import * as THREE from "three"

import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Textarea } from "@/components/ui/textarea"
import { Label } from "@/components/ui/label"
import { 
  MapPin, 
  Phone, 
  Mail, 
  Clock,
  Linkedin,
  Github,
  Send,
  CheckCircle
} from "lucide-react"

// --- 3D ANIMATION COMPONENT ---
function Background3D() {
  const sphereRef = useRef<THREE.Mesh>(null!)
  
  return (
    <group>
      <Stars radius={100} depth={50} count={5000} factor={4} saturation={0} fade speed={1} />
      <Float speed={2} rotationIntensity={1} floatIntensity={2}>
        <Sphere ref={sphereRef} args={[1, 100, 100]} position={[2, 0, 0]}>
          <MeshDistortMaterial
            color="#6366f1"
            attach="material"
            distort={0.5}
            speed={2}
            roughness={0}
          />
        </Sphere>
      </Float>
      <ambientLight intensity={0.5} />
      <pointLight position={[10, 10, 10]} intensity={1} />
    </group>
  )
}

// --- DATA (Unchanged) ---
const contactInfo = [
  {
    icon: MapPin,
    title: "Office Address",
    content: "123 Tech Park, Silicon Valley\nSan Francisco, CA 94102, USA",
    link: "https://maps.google.com",
  },
  {
    icon: Phone,
    title: "Phone Number",
    content: "+1 (234) 567-890",
    link: "tel:+1234567890",
  },
  {
    icon: Mail,
    title: "Email Address",
    content: "info@quantixlab.com",
    link: "mailto:info@quantixlab.com",
  },
  {
    icon: Clock,
    title: "Business Hours",
    content: "Monday - Friday\n9:00 AM - 6:00 PM PST",
  },
]

const social = [
  { name: "LinkedIn", href: "https://linkedin.com/company/quantixlab", icon: Linkedin },
  { name: "GitHub", href: "https://github.com/quantixlab", icon: Github },
]

export default function ContactPage() {
  const [submitted, setSubmitted] = useState(false)
  const [loading, setLoading] = useState(false)

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault()
    setLoading(true)
    await new Promise((resolve) => setTimeout(resolve, 1000))
    setLoading(false)
    setSubmitted(true)
  }

  return (
    <div className="flex flex-col relative bg-background overflow-hidden">
      
      {/* GLOBAL 3D CANVAS BACKGROUND */}
      <div className="fixed inset-0 -z-10 pointer-events-none opacity-40">
        <Canvas camera={{ position: [0, 0, 5] }}>
          <Suspense fallback={null}>
            <Background3D />
          </Suspense>
        </Canvas>
      </div>

      {/* Hero Section */}
      <section className="relative overflow-hidden py-20 lg:py-28">
        <div className="absolute inset-0 -z-10">
          <div className="absolute inset-0 bg-[linear-gradient(to_right,#8080800a_1px,transparent_1px),linear-gradient(to_bottom,#8080800a_1px,transparent_1px)] bg-[size:14px_24px]" />
        </div>
        <div className="mx-auto max-w-7xl px-4 lg:px-8">
          <div className="mx-auto max-w-3xl text-center">
            <span className="text-sm font-semibold text-primary uppercase tracking-wider">
              Contact Us
            </span>
            <h1 className="mt-4 text-4xl font-bold tracking-tight text-foreground sm:text-5xl text-balance">
              Get in Touch
            </h1>
            <p className="mt-6 text-lg text-muted-foreground leading-relaxed">
              Have a project in mind or want to learn more about our services? 
              We'd love to hear from you. Reach out and let's start a conversation.
            </p>
          </div>
        </div>
      </section>

      {/* Contact Form & Info */}
      <section className="py-20 lg:py-28 backdrop-blur-[2px]">
        <div className="mx-auto max-w-7xl px-4 lg:px-8">
          <div className="grid gap-12 lg:grid-cols-2 lg:gap-16">
            
            {/* Contact Form (Original Logic preserved) */}
            <div className="bg-background/80 backdrop-blur-md p-8 rounded-2xl border border-border shadow-sm">
              <h2 className="text-2xl font-bold text-foreground">Send Us a Message</h2>
              <p className="mt-2 text-muted-foreground">
                Fill out the form below and we'll get back to you within 24 hours.
              </p>

              {submitted ? (
                <div className="mt-8 rounded-xl border border-border bg-muted/30 p-8 text-center">
                  <div className="mx-auto flex h-16 w-16 items-center justify-center rounded-full bg-primary/10">
                    <CheckCircle className="h-8 w-8 text-primary" />
                  </div>
                  <h3 className="mt-4 text-xl font-semibold text-foreground">Message Sent!</h3>
                  <p className="mt-2 text-muted-foreground">
                    Thank you for reaching out. We'll get back to you shortly.
                  </p>
                  <Button className="mt-6" onClick={() => setSubmitted(false)}>
                    Send Another Message
                  </Button>
                </div>
              ) : (
                <form onSubmit={handleSubmit} className="mt-8 space-y-6">
                  <div className="grid gap-6 sm:grid-cols-2">
                    <div className="space-y-2">
                      <Label htmlFor="firstName">First Name</Label>
                      <Input id="firstName" name="firstName" placeholder="John" required />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="lastName">Last Name</Label>
                      <Input id="lastName" name="lastName" placeholder="Doe" required />
                    </div>
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="email">Email Address</Label>
                    <Input id="email" name="email" type="email" placeholder="john@example.com" required />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="company">Company (Optional)</Label>
                    <Input id="company" name="company" placeholder="Your Company" />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="subject">Subject</Label>
                    <Input id="subject" name="subject" placeholder="How can we help?" required />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="message">Message</Label>
                    <Textarea id="message" name="message" placeholder="Tell us about your project..." rows={5} required />
                  </div>

                  <Button type="submit" size="lg" className="w-full transition-transform active:scale-95" disabled={loading}>
                    {loading ? "Sending..." : (
                      <span className="flex items-center">
                        Send Message <Send className="ml-2 h-4 w-4" />
                      </span>
                    )}
                  </Button>
                </form>
              )}
            </div>

            {/* Contact Info (Original Details preserved) */}
            <div>
              <h2 className="text-2xl font-bold text-foreground">Contact Information</h2>
              <p className="mt-2 text-muted-foreground">
                You can also reach us through any of the following channels.
              </p>

              <div className="mt-8 space-y-6">
                {contactInfo.map((item) => (
                  <div
                    key={item.title}
                    className="flex items-start gap-4 rounded-xl border border-border bg-background/60 backdrop-blur-sm p-5 transition-all hover:shadow-lg hover:border-primary/30 group"
                  >
                    <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-lg bg-primary/10 group-hover:bg-primary group-hover:text-white transition-colors">
                      <item.icon className="h-6 w-6 text-primary group-hover:text-white" />
                    </div>
                    <div>
                      <h3 className="font-semibold text-foreground">{item.title}</h3>
                      {item.link ? (
                        <a
                          href={item.link}
                          target={item.link.startsWith("http") ? "_blank" : undefined}
                          rel={item.link.startsWith("http") ? "noopener noreferrer" : undefined}
                          className="mt-1 text-muted-foreground hover:text-primary whitespace-pre-line"
                        >
                          {item.content}
                        </a>
                      ) : (
                        <p className="mt-1 text-muted-foreground whitespace-pre-line">{item.content}</p>
                      )}
                    </div>
                  </div>
                ))}
              </div>

              {/* Social & Map */}
              <div className="mt-8">
                <h3 className="font-semibold text-foreground">Follow Us</h3>
                <div className="mt-4 flex gap-4">
                  {social.map((item) => (
                    <a
                      key={item.name}
                      href={item.href}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="flex h-12 w-12 items-center justify-center rounded-full border border-border bg-background text-muted-foreground transition-all hover:bg-primary hover:text-primary-foreground hover:border-primary"
                    >
                      <item.icon className="h-5 w-5" />
                    </a>
                  ))}
                </div>
              </div>

              <div className="mt-8">
                <h3 className="font-semibold text-foreground mb-4">Our Location</h3>
                <div className="aspect-video rounded-xl border border-border bg-background/50 backdrop-blur-sm flex items-center justify-center relative overflow-hidden group">
                  <div className="absolute inset-0 bg-primary/5 opacity-0 group-hover:opacity-100 transition-opacity" />
                  <div className="z-10 text-center">
                    <MapPin className="h-12 w-12 text-primary/30 mx-auto group-hover:scale-110 transition-transform" />
                    <p className="mt-2 text-sm text-muted-foreground">
                      123 Tech Park, Silicon Valley<br />
                      San Francisco, CA 94102
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* CTA Section */}
      <section className="bg-primary py-20 lg:py-28 relative overflow-hidden">
        {/* Decorative 3D-like circles */}
        <div className="absolute top-0 right-0 -translate-y-1/2 translate-x-1/3 w-96 h-96 bg-white/10 rounded-full blur-3xl" />
        <div className="mx-auto max-w-7xl px-4 lg:px-8 relative z-10">
          <div className="mx-auto max-w-3xl text-center">
            <h2 className="text-3xl font-bold text-primary-foreground sm:text-4xl">
              Ready to Start Your Project?
            </h2>
            <p className="mt-4 text-lg text-primary-foreground/80">
              Schedule a free consultation call with our team to discuss your requirements.
            </p>
            <Button 
              size="lg" 
              className="mt-8 bg-primary-foreground text-primary hover:bg-primary-foreground/90 font-bold"
            >
              Schedule a Call
            </Button>
          </div>
        </div>
      </section>
    </div>
  )
}